import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    b = list(map(int, input().split()))

    if n == 1:
        print("1")
        return

    result = ['0'] * n

    for start in range(n):
        max_a = a[start]
        max_b = b[start]
        absorbed = 1
        changed = True
        while changed:
            changed = False
            for i in range(n):
                if i == start:
                    continue
                # Can beat player i if a[i] < max_a or b[i] < max_b
                if a[i] < max_a or b[i] < max_b:
                    new_max_a = max(max_a, a[i])
                    new_max_b = max(max_b, b[i])
                    if new_max_a != max_a or new_max_b != max_b:
                        changed = True
                        max_a = new_max_a
                        max_b = new_max_b
        # Check if all players can be absorbed
        can_win = True
        for i in range(n):
            if i == start:
                continue
            if not (a[i] < max_a or b[i] < max_b):
                can_win = False
                break
        if can_win:
            result[start] = '1'

    print(''.join(result))

t = int(input())
for _ in range(t):
    solve()
